using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;

namespace sv_9a1783e78c14472399b91e077abd5cd6.Auth;

/// <summary>
/// Persists the authentication state to the client so that the WebAssembly runtime
/// can reconstruct the user's identity after the handoff from server prerendering.
/// </summary>
public class PersistingAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentComponentState;
    private readonly AuthenticationStateProvider _inner;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(
        PersistentComponentState persistentComponentState,
        [FromKeyedServices("inner")] AuthenticationStateProvider inner)
    {
        _persistentComponentState = persistentComponentState;
        _inner = inner;
        _subscription = _persistentComponentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        _authStateTask ??= _inner.GetAuthenticationStateAsync();
        return _authStateTask;
    }

    private async Task OnPersistingAsync()
    {
        var authState = await GetAuthenticationStateAsync();
        var principal = authState.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var claims = principal.Claims.Select(c => new ClaimData(c.Type, c.Value)).ToArray();
            _persistentComponentState.PersistAsJson("auth_state", claims);
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

public record ClaimData(string Type, string Value);

